 32→    }
 33→    if (title.length > 200) {
 34→        throw { status: 400, error: 'title must be 200 characters or less' };
 35→    }
 36→    if (description && description.length > 2000) {
 37→        throw { status: 400, error: 'description must be 2000 characters or less' };
 38→    }
 39→
 40→    const validStatuses = ['ongoing', 'completed', 'hiatus'];
 41→    const validPrivacy = ['public', 'private'];
 42→    const storyStatus = validStatuses.includes(status) ? status : 'ongoing';
 43→    const storyPrivacy = validPrivacy.includes(privacy) ? privacy : 'public';
 44→
 45→    let parsedTags = [];
 46→    if (tags) {
 47→        try {
 48→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 49→            if (!Array.isArray(parsedTags)) parsedTags = [];
 50→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
 51→        } catch {
 52→            parsedTags = [];
 53→        }
 54→    }
 55→
 56→    let coverUrl = null;
 57→    if (coverFile) {
 58→        coverUrl = await imageUploader(coverFile, userId, 'story-covers');
 59→    }
 60→
 61→    const { data, error } = await supabase
 62→        .from('stories')
 63→        .insert({
 64→            author_id: userId,
 65→            title: title.trim(),
 66→            description: (description || '').trim(),
 67→            cover_url: coverUrl,
 68→            status: storyStatus,
 69→            privacy: storyPrivacy,
 70→            tags: parsedTags,
 71→        })
 72→        .select('*')
 73→        .single();
 74→
 75→    if (error) {
 76→        console.error('supabase error creating story:', error.message);
 77→        throw { status: 500, error: 'failed to create story' };
 78→    }
 79→
 80→    return data;
 81→};
