 83→export const getStoriesService = async (limit, before, status, tag, userId) => {
 84→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 10, 1), 20);
 85→
 86→    let query = supabase
 87→        .from('stories')
 88→        .select('*')
 89→        .eq('privacy', 'public')
 90→        .order('created_at', { ascending: false })
 91→        .limit(parsedLimit + 1);
 92→
 93→    if (before) {
 94→        query = query.lt('created_at', before);
 95→    }
 96→    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
 97→        query = query.eq('status', status);
 98→    }
 99→    if (tag) {
100→        query = query.contains('tags', [tag]);
101→    }
102→
103→    const { data, error } = await query;
104→
105→    if (error) {
106→        console.error('supabase error fetching stories:', error.message);
107→        throw { status: 500, error: 'failed to fetch stories' };
108→    }
109→
110→    if (!data || data.length === 0) {
111→        return { data: [], hasMore: false };
112→    }
113→
114→    // Batch-fetch author profiles
115→    const authorMap = await fetchAuthorProfiles(data.map(s => s.author_id));
116→
117→    // Fetch user interaction flags if logged in
118→    let userVotedSet = new Set();
119→    let userLibrarySet = new Set();
120→
121→    if (userId) {
122→        const storyIds = data.map(s => s.id);
123→        const [votes, library] = await Promise.all([
124→            supabase.from('story_votes').select('story_id').in('story_id', storyIds).eq('user_id', userId),
125→            supabase.from('story_library').select('story_id').in('story_id', storyIds).eq('user_id', userId),
126→        ]);
127→
128→        if (votes.data) userVotedSet = new Set(votes.data.map(v => v.story_id));
129→        if (library.data) userLibrarySet = new Set(library.data.map(l => l.story_id));
130→    }
131→
132→    const formatted = data.map(story => ({
133→        ...story,
134→        users: authorMap[story.author_id] || null,
135→        has_voted: userVotedSet.has(story.id),
136→        in_library: userLibrarySet.has(story.id),
137→    }));
138→
139→    const hasMore = data.length > parsedLimit;
140→    const sliced = hasMore ? formatted.slice(0, parsedLimit) : formatted;
141→
142→    return { data: sliced, hasMore };
143→};
