  1→import React, { useState, useRef, useEffect } from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useStoryDetail } from '../hooks/useStoryData';
  5→import { useCreateStory, useUpdateStory } from '../hooks/useStoryMutations';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryEditor.css';
  9→
 10→const TAG_SUGGESTIONS = [
 11→    'Fantasy', 'Romance', 'Sci-Fi', 'Mystery', 'Thriller',
 12→    'Horror', 'Adventure', 'Drama', 'Comedy', 'Poetry',
 13→    'Slice of Life', 'Action', 'Historical', 'Fanfiction',
 14→];
 15→
 16→const StoryEditor = () => {
 17→    const { storyId } = useParams();
 18→    const isEdit = !!storyId;
 19→    const navigate = useNavigate();
 20→    const { session } = useAuth();
 21→    const token = session?.access_token;
 22→
 23→    const { data: existingStory, isLoading: loadingStory } = useStoryDetail(
 24→        isEdit ? storyId : null,
 25→        token
 26→    );
 27→
 28→    const createMutation = useCreateStory(token);
 29→    const updateMutation = useUpdateStory(token);
 30→
 31→    const [title, setTitle] = useState('');
 32→    const [description, setDescription] = useState('');
 33→    const [status, setStatus] = useState('ongoing');
 34→    const [privacy, setPrivacy] = useState('public');
 35→    const [tags, setTags] = useState([]);
 36→    const [tagInput, setTagInput] = useState('');
 37→    const [coverPreview, setCoverPreview] = useState(null);
 38→    const [coverFile, setCoverFile] = useState(null);
 39→    const coverInputRef = useRef(null);
 40→
 41→    useEffect(() => {
 42→        if (isEdit && existingStory) {
 43→            setTitle(existingStory.title || '');
 44→            setDescription(existingStory.description || '');
 45→            setStatus(existingStory.status || 'ongoing');
 46→            setPrivacy(existingStory.privacy || 'public');
 47→            setTags(existingStory.tags || []);
 48→            if (existingStory.cover_url) {
 49→                setCoverPreview(existingStory.cover_url);
 50→            }
 51→        }
 52→    }, [isEdit, existingStory]);
 53→
 54→    const handleCoverChange = (e) => {
 55→        const file = e.target.files[0];
 56→        if (file) {
 57→            setCoverFile(file);
 58→            const reader = new FileReader();
 59→            reader.onloadend = () => setCoverPreview(reader.result);
 60→            reader.readAsDataURL(file);
 61→        }
 62→    };
 63→
 64→    const handleAddTag = (tag) => {
 65→        const trimmed = tag.trim();
 66→        if (trimmed && !tags.includes(trimmed) && tags.length < 10) {
 67→            setTags([...tags, trimmed]);
 68→        }
 69→        setTagInput('');
 70→    };
 71→
 72→    const handleRemoveTag = (tag) => {
 73→        setTags(tags.filter(t => t !== tag));
 74→    };
 75→
 76→    const handleTagKeyDown = (e) => {
 77→        if (e.key === 'Enter' || e.key === ',') {
 78→            e.preventDefault();
 79→            handleAddTag(tagInput);
 80→        }
 81→    };
 82→
 83→    const handleSubmit = async (e) => {
 84→        e.preventDefault();
 85→        if (!title.trim()) return;
 86→
 87→        const formData = new FormData();
 88→        formData.append('title', title.trim());
 89→        formData.append('description', description.trim());
 90→        formData.append('status', status);
 91→        formData.append('privacy', privacy);
 92→        formData.append('tags', JSON.stringify(tags));
 93→        if (coverFile) {
 94→            formData.append('image', coverFile);
 95→        }
 96→
 97→        try {
 98→            if (isEdit) {
 99→                await updateMutation.mutateAsync({ storyId, formData });
100→                navigate(`/home/stories/${storyId}/manage`);
101→            } else {
102→                const newStory = await createMutation.mutateAsync(formData);
103→                navigate(`/home/stories/${newStory.id}/manage`);
104→            }
105→        } catch (err) {
106→            console.error('Failed to save story:', err);
107→        }
108→    };
109→
110→    const isSaving = createMutation.isPending || updateMutation.isPending;
111→
112→    if (isEdit && loadingStory) {
113→        return (
114→            <div className="story-editor-page">
115→                <div className="story-editor-loading">
116→                    <BeatLoader size={10} color="var(--text-muted)" />
117→                </div>
118→            </div>
119→        );
120→    }
121→
122→    return (
123→        <motion.div
124→            className="story-editor-page"
125→            initial={{ opacity: 0, y: 12 }}
126→            animate={{ opacity: 1, y: 0 }}
127→            transition={{ duration: 0.2 }}
128→        >
129→            <div className="story-editor-container">
130→                <div className="story-editor-header">
131→                    <button className="story-editor-back" onClick={() => navigate(-1)}>
132→                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
133→                            <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
134→                        </svg>
135→                    </button>
136→                    <h2>{isEdit ? 'Edit Story' : 'New Story'}</h2>
137→                </div>
138→
139→                <form onSubmit={handleSubmit} className="story-editor-form">
140→                    {/* Cover image */}
141→                    <div
142→                        className="story-editor-cover"
143→                        onClick={() => coverInputRef.current?.click()}
144→                    >
145→                        {coverPreview ? (
146→                            <img src={coverPreview} alt="Cover preview" />
147→                        ) : (
148→                            <div className="story-editor-cover-placeholder">
149→                                <svg xmlns="http://www.w3.org/2000/svg" width="36" height="36" viewBox="0 0 24 24" fill="var(--text-muted)">
150→                                    <path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2zM8.5 13.5l2.5 3.01L14.5 12l4.5 6H5l3.5-4.5z"/>
151→                                </svg>
152→                                <span>Add cover image</span>
153→                            </div>
154→                        )}
155→                        <input
156→                            ref={coverInputRef}
157→                            type="file"
158→                            accept="image/*"
159→                            onChange={handleCoverChange}
160→                            style={{ display: 'none' }}
161→                        />
162→                    </div>
163→
164→                    {/* Title */}
165→                    <div className="story-editor-field">
166→                        <label className="story-editor-label">
167→                            Title
168→                            <span className="story-editor-counter">{title.length}/200</span>
169→                        </label>
170→                        <input
171→                            type="text"
172→                            className="story-editor-input"
173→                            value={title}
174→                            onChange={(e) => setTitle(e.target.value)}
175→                            maxLength={200}
176→                            placeholder="Give your story a title"
177→                            required
178→                        />
179→                    </div>
180→
181→                    {/* Description */}
182→                    <div className="story-editor-field">
183→                        <label className="story-editor-label">
184→                            Description
185→                            <span className="story-editor-counter">{description.length}/2000</span>
186→                        </label>
187→                        <textarea
188→                            className="story-editor-textarea"
189→                            value={description}
190→                            onChange={(e) => setDescription(e.target.value)}
191→                            maxLength={2000}
192→                            placeholder="What is your story about?"
193→                            rows={4}
194→                        />
195→                    </div>
196→
197→                    {/* Status & Privacy */}
198→                    <div className="story-editor-row">
199→                        <div className="story-editor-field story-editor-field-half">
200→                            <label className="story-editor-label">Status</label>
201→                            <select
202→                                className="story-editor-select"
203→                                value={status}
204→                                onChange={(e) => setStatus(e.target.value)}
205→                            >
206→                                <option value="ongoing">Ongoing</option>
207→                                <option value="completed">Completed</option>
208→                                <option value="hiatus">Hiatus</option>
209→                            </select>
210→                        </div>
211→                        <div className="story-editor-field story-editor-field-half">
212→                            <label className="story-editor-label">Privacy</label>
213→                            <select
214→                                className="story-editor-select"
215→                                value={privacy}
216→                                onChange={(e) => setPrivacy(e.target.value)}
217→                            >
218→                                <option value="public">Public</option>
219→                                <option value="private">Private</option>
220→                            </select>
221→                        </div>
222→                    </div>
223→
224→                    {/* Tags */}
225→                    <div className="story-editor-field">
226→                        <label className="story-editor-label">Tags ({tags.length}/10)</label>
227→                        <div className="story-editor-tags-container">
228→                            {tags.map((tag) => (
229→                                <span key={tag} className="story-editor-tag">
230→                                    {tag}
231→                                    <button
232→                                        type="button"
233→                                        className="story-editor-tag-remove"
234→                                        onClick={() => handleRemoveTag(tag)}
235→                                    >
236→                                        &times;
237→                                    </button>
238→                                </span>
239→                            ))}
240→                            {tags.length < 10 && (
241→                                <input
242→                                    type="text"
243→                                    className="story-editor-tag-input"
244→                                    value={tagInput}
245→                                    onChange={(e) => setTagInput(e.target.value)}
246→                                    onKeyDown={handleTagKeyDown}
247→                                    placeholder="Add a tag..."
248→                                />
249→                            )}
250→                        </div>
251→                        <div className="story-editor-tag-suggestions">
252→                            {TAG_SUGGESTIONS
253→                                .filter(s => !tags.includes(s))
254→                                .slice(0, 8)
255→                                .map((s) => (
256→                                    <button
257→                                        key={s}
258→                                        type="button"
259→                                        className="story-editor-tag-suggestion"
260→                                        onClick={() => handleAddTag(s)}
261→                                    >
262→                                        + {s}
263→                                    </button>
264→                                ))}
265→                        </div>
266→                    </div>
267→
268→                    {/* Submit */}
269→                    <button
270→                        type="submit"
271→                        className="story-editor-submit"
272→                        disabled={!title.trim() || isSaving}
273→                    >
274→                        {isSaving ? (
275→                            <BeatLoader size={8} color="var(--bg-primary)" />
276→                        ) : (
277→                            isEdit ? 'Save Changes' : 'Create Story'
278→                        )}
279→                    </button>
280→                </form>
281→            </div>
282→        </motion.div>
283→    );
284→};
