215→export const updateStoryService = async (storyId, userId, updates, coverFile) => {
216→    if (!storyId || !userId) {
217→        throw { status: 400, error: 'storyId and userId are required' };
218→    }
219→
220→    // Verify ownership
221→    const { data: existing, error: fetchError } = await supabase
222→        .from('stories')
223→        .select('author_id')
224→        .eq('id', storyId)
225→        .single();
226→
227→    if (fetchError || !existing) {
228→        throw { status: 404, error: 'story not found' };
229→    }
230→    if (existing.author_id !== userId) {
231→        throw { status: 403, error: 'not authorized to update this story' };
232→    }
233→
234→    const updateData = {};
235→    if (updates.title !== undefined) {
236→        if (!updates.title || updates.title.trim().length === 0) {
237→            throw { status: 400, error: 'title cannot be empty' };
238→        }
239→        updateData.title = updates.title.trim();
240→    }
241→    if (updates.description !== undefined) {
242→        updateData.description = (updates.description || '').trim();
243→    }
244→    if (updates.status !== undefined && ['ongoing', 'completed', 'hiatus'].includes(updates.status)) {
245→        updateData.status = updates.status;
246→    }
247→    if (updates.privacy !== undefined && ['public', 'private'].includes(updates.privacy)) {
248→        updateData.privacy = updates.privacy;
249→    }
250→    if (updates.tags !== undefined) {
251→        let parsedTags = [];
252→        try {
253→            parsedTags = typeof updates.tags === 'string' ? JSON.parse(updates.tags) : updates.tags;
254→            if (!Array.isArray(parsedTags)) parsedTags = [];
255→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
256→        } catch {
257→            parsedTags = [];
258→        }
259→        updateData.tags = parsedTags;
260→    }
261→
262→    if (coverFile) {
263→        updateData.cover_url = await imageUploader(coverFile, userId, 'story-covers');
264→    }
265→
266→    if (Object.keys(updateData).length === 0) {
267→        throw { status: 400, error: 'no valid fields to update' };
268→    }
269→
270→    const { data, error } = await supabase
271→        .from('stories')
272→        .update(updateData)
273→        .eq('id', storyId)
274→        .select('*')
275→        .single();
276→
277→    if (error) {
278→        console.error('supabase error updating story:', error.message);
279→        throw { status: 500, error: 'failed to update story' };
280→    }
281→
282→    return data;
283→};
